np-art-backdrop:
position: absolute; inset: -20% -20% 40% -20%;
    background: radial-gradient(circle at 50% 30%, #6B4A8C 0%, #422E5C 45%, transparent 72%);
    filter: blur(40px); opacity: 0.85;

np-art:
width: 232px; height: 232px; border-radius: 8px; margin: 26px auto 0;
    background: linear-gradient(140deg, #C13584 0%, #833AB4 45%, #5851DB 100%);
    box-shadow: 0 24px 60px -20px rgba(0,0,0,0.7); position: relative; z-index: 2; overflow: hidden;
